// InvalidStateException.java
public class InvalidStateException extends BusinessException {
    private String currentState;
    private String attemptedOperation;

    public InvalidStateException(String message) {
        super(message);
    }

    public InvalidStateException(String message, String currentState, 
                                String attemptedOperation) {
        super(message);
        this.currentState = currentState;
        this.attemptedOperation = attemptedOperation;
    }
}

// GlobalExceptionHandler - Handlers específicos
@RestControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    @ExceptionHandler(NotFoundException.class)
    public ResponseEntity<ErrorResponse> handleNotFound(
            NotFoundException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.NOT_FOUND.value(),
            "Not Found",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(DuplicateResourceException.class)
    public ResponseEntity<ErrorResponse> handleDuplicate(
            DuplicateResourceException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.CONFLICT.value(),
            "Conflict",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.CONFLICT).body(error);
    }

    @ExceptionHandler(InvalidStateException.class)
    public ResponseEntity<ErrorResponse> handleInvalidState(
            InvalidStateException ex, WebRequest request) {
        ErrorResponse error = new ErrorResponse(
            HttpStatus.BAD_REQUEST.value(),
            "Invalid State",
            ex.getMessage(),
            request.getDescription(false).replace("uri=", "")
        );
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(error);
    }
}

// Uso en Service
public Customer create(Customer customer) {
    // Validar duplicado por email
    if (customerRepository.existsByEmail(customer.getEmail())) {
        throw new DuplicateResourceException(
            "Customer with email " + customer.getEmail() + " already exists"
        );
    }

    // Validar estado
    if (customer.getStatus().equals("INACTIVE") && 
        customer.getProductIds().size() > 0) {
        throw new InvalidStateException(
            "Cannot assign products to inactive customer",
            "INACTIVE",
            "ASSIGN_PRODUCTS"
        );
    }

    return customerRepository.save(customer);
}

// CustomerService - Validar respuestas de Product API
@Service
public class CustomerService {

    @Autowired
    private WebClient productWebClient;

    public Customer create(Customer customer) {
        // Validar que productos existen
        if (customer.getProductIds() != null) {
            for (Long productId : customer.getProductIds()) {
                validateProductExists(productId);
            }
        }

        return customerRepository.save(customer);
    }

    private void validateProductExists(Long productId) {
        try {
            Product product = productWebClient.get()
                .uri("/product/{id}", productId)
                .retrieve()
                .onStatus(
                    status -> status.is4xxClientError(),
                    clientResponse -> {
                        if (clientResponse.statusCode().equals(HttpStatus.NOT_FOUND)) {
                            return Mono.error(new NotFoundException(
                                "Product with ID " + productId + " not found"
                            ));
                        }
                        return Mono.error(new IllegalArgumentException(
                            "Invalid product ID: " + productId
                        ));
                    }
                )
                .onStatus(
                    status -> status.is5xxServerError(),
                    clientResponse -> {
                        log.error("Product service error: {}", 
                                 clientResponse.statusCode());
                        return Mono.error(new ServiceUnavailableException(
                            "Product service is currently unavailable"
                        ));
                    }
                )
                .bodyToMono(Product.class)
                .block();

        } catch (WebClientException e) {
            log.error("Error calling Product service", e);
            throw new ServiceUnavailableException(
                "Unable to validate product: " + e.getMessage()
            );
        }
    }
}

// ServiceUnavailableException.java
public class ServiceUnavailableException extends BusinessException {
    public ServiceUnavailableException(String message) {
        super(message);
    }
}

// GlobalExceptionHandler - Handler para service unavailable
@ExceptionHandler(ServiceUnavailableException.class)
public ResponseEntity<ErrorResponse> handleServiceUnavailable(
        ServiceUnavailableException ex, WebRequest request) {

    log.error("Service unavailable: {}", ex.getMessage());

    ErrorResponse error = new ErrorResponse(
        HttpStatus.SERVICE_UNAVAILABLE.value(),
        "Service Unavailable",
        ex.getMessage(),
        request.getDescription(false).replace("uri=", "")
    );

    return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE)
        .body(error);
}

